import { Stopwatch } from '../src/intervalTimer'

let failures = 0
async function check(name: string, got: unknown, want: unknown) {
  got = await got  // resolve promises transparently
  const ok = JSON.stringify(got) === JSON.stringify(want)
  console.log(`  ${ok ? 'PASS' : 'FAIL'} — ${name}`)
  if (!ok) {
    console.log(`       got:  ${JSON.stringify(got)}`)
    console.log(`       want: ${JSON.stringify(want)}`)
    failures++
  }
}

;(async () => {
await check("not running initially", new Stopwatch().isRunning(), false)
await check("running after start", new Stopwatch().start().isRunning(), true)
await check("not running after stop", (() => { const s = new Stopwatch(); s.start(); s.stop(); return s.isRunning() })(), false)
await check("elapsed >= 0", new Stopwatch().start().elapsedMs() >= 0, true)
await check("reset clears", (() => { const s = new Stopwatch(); s.start(); s.stop(); s.reset(); return s.elapsedMs() })(), 0)
await check("laps empty initially", new Stopwatch().getLaps(), [])
await check("stop returns elapsed", typeof new Stopwatch().start().stop() === "number", true)
console.log(failures === 0 ? 'ALL PASS' : `${failures} FAILURE(S)`)
process.exit(failures === 0 ? 0 : 1)
})()
